lines = data.strip().split('\n')
headers = lines[0].split('\t')

results = []
for line in lines[1:]:
    cols = line.split('\t')
    if len(cols) < 25: continue
    
    emp_id = cols[0]
    emp_name = cols[1]
    amount_gross = cols[7].replace('$', '').replace(',', '')
    status = cols[19]
    delivered_by = cols[21]
    amount_net = cols[23].replace('$', '').replace(',', '')
    
    try:
        g = float(amount_gross) if amount_gross else 0
        n = float(amount_net) if amount_net else 0
    except:
        g = 0
        n = 0
        
    results.append({
        'id': emp_id,
        'name': emp_name,
        'gross': g,
        'net': n,
        'status': status,
        'delivered_by': delivered_by
    })

# Group by name
delivered_totals_gross = {}
delivered_totals_net = {}
for r in results:
    if r['status'] == 'Delivered':
        delivered_totals_gross[r['name']] = delivered_totals_gross.get(r['name'], 0) + r['gross']
        delivered_totals_net[r['name']] = delivered_totals_net.get(r['name'], 0) + r['net']

print("Totals for PROVIDED DATA (Delivered Status Only):")
print(f"{'Name':30} | {'Gross':>10} | {'Net':>10}")
print("-" * 55)
for name in sorted(delivered_totals_gross.keys()):
    g = delivered_totals_gross[name]
    n = delivered_totals_net[name]
    print(f"{name:30} | ${g:10,.2f} | ${n:10,.2f}")

grand_gross = sum(delivered_totals_gross.values())
grand_net = sum(delivered_totals_net.values())
print("-" * 55)
print(f"{'GRAND TOTAL':30} | ${grand_gross:10,.2f} | ${grand_net:10,.2f}")
